/**
 * BTForm — top-level form coordinator. Mirrors what you'd write with a
 * plain `<form>` element, but adds:
 *
 *   - A single `validator` prop (function OR per-field map) that runs once
 *     per render and produces a `field → error` map.
 *   - A context that BT input components subscribe to via their `name` prop —
 *     `value`, `onChange`, `onBlur`, and `error` wire automatically. No
 *     prop-spreading per input required.
 *   - `onSubmit` only fires when the form is valid. Browser-native HTML5
 *     validation tooltips are suppressed by default (we own the UI).
 *   - Errors gated on `touched` OR `submitted` so untouched fields stay
 *     clean until the user attempts submit.
 *
 * Per-input `errorText` and `validator` props still work — explicit prop
 * always wins. Use BTForm for the *form-level* shape; per-input rules layer
 * on top for client-side feedback that doesn't need cross-field context.
 */
import * as React from 'react';
import { BTFormContext } from './BTFormContext';
import type {
  BTFormContextValue,
  BTFormFieldValidator,
  BTFormProps,
  BTFormState,
  BTFormStatus,
  BTFormValidator,
} from './BTForm.types';

function runValidator<T extends Record<string, unknown>>(
  validator: BTFormValidator<T> | undefined,
  values: T,
): Partial<Record<keyof T, string | null>> {
  if (!validator) return {};
  if (typeof validator === 'function') {
    const raw = validator(values) ?? {};
    // Normalize undefined → null so downstream consumers don't have to
    // special-case "not set" vs "no error".
    const out: Partial<Record<keyof T, string | null>> = {};
    for (const k of Object.keys(raw) as Array<keyof T>) {
      const v = raw[k];
      out[k] = v == null ? null : v;
    }
    return out;
  }
  // Per-field map form.
  const out: Partial<Record<keyof T, string | null>> = {};
  for (const k of Object.keys(values) as Array<keyof T>) {
    const fn = (validator as Record<string, BTFormFieldValidator<unknown, T>>)[
      k as string
    ];
    if (!fn) continue;
    const result = fn(values[k], values);
    out[k] = result == null ? null : result;
  }
  return out;
}

export function BTForm<T extends Record<string, unknown>>({
  initialValues,
  validation,
  onSubmit,
  onInvalid,
  children,
  className,
  id,
  noValidate = true,
}: BTFormProps<T>) {
  const [values, setValues] = React.useState<T>(initialValues);
  const [touched, setTouched] = React.useState<Partial<Record<keyof T, boolean>>>({});
  const [submitted, setSubmitted] = React.useState(false);
  const [status, setStatus] = React.useState<BTFormStatus>('idle');

  // Errors recompute each render. Cheap unless the validator is expensive —
  // consumer can wrap the validator in useCallback / memoize per field if so.
  const errors = React.useMemo(
    () => runValidator(validation, values),
    [validation, values],
  );
  const isValid = React.useMemo(
    () => Object.values(errors).every((e) => !e),
    [errors],
  );

  const errorFor = React.useCallback(
    (name: keyof T): string | null =>
      submitted || touched[name] ? errors[name] ?? null : null,
    [submitted, touched, errors],
  );

  const setField = React.useCallback(
    <K extends keyof T>(name: K, value: T[K]) => {
      setValues((s) => ({ ...s, [name]: value }));
    },
    [],
  );

  const touch = React.useCallback((name: keyof T) => {
    setTouched((t) => ({ ...t, [name]: true }));
  }, []);

  const reset = React.useCallback(() => {
    setValues(initialValues);
    setTouched({});
    setSubmitted(false);
    setStatus('idle');
  }, [initialValues]);

  const validate = React.useCallback(() => errors, [errors]);

  const formState: BTFormState<T> = {
    values,
    errors,
    touched,
    submitted,
    status,
    isValid,
    errorFor,
    setField,
    touch,
    reset,
    validate,
  };

  async function handleSubmit(e: React.FormEvent<HTMLFormElement>) {
    e.preventDefault();
    setSubmitted(true);
    if (!isValid) {
      setStatus('submitted-invalid');
      onInvalid?.(errors);
      return;
    }
    try {
      await onSubmit?.(values);
      setStatus('submitted-success');
    } catch {
      // User-thrown errors leave the form in `submitted-invalid` so the UI
      // can render a generic "submission failed" alongside field errors.
      setStatus('submitted-invalid');
      onInvalid?.(errors);
    }
  }

  function handleReset(e: React.FormEvent<HTMLFormElement>) {
    e.preventDefault();
    reset();
  }

  // Narrow the public context slice (omit setters that re-init values).
  const contextValue = React.useMemo(
    () => ({
      values,
      errors,
      touched,
      submitted,
      errorFor,
      setField,
      touch,
    }),
    [values, errors, touched, submitted, errorFor, setField, touch],
  );

  return (
    <BTFormContext.Provider
      value={contextValue as unknown as BTFormContextValue}
    >
      <form
        id={id}
        className={className}
        noValidate={noValidate}
        onSubmit={handleSubmit}
        onReset={handleReset}
      >
        {typeof children === 'function' ? children(formState) : children}
      </form>
    </BTFormContext.Provider>
  );
}

BTForm.displayName = 'BTForm';

import type React from 'react';

/**
 * Per-field validator. Receives the field's current value and the full
 * `values` snapshot for cross-field rules (e.g. "confirm-password matches
 * password"). Return `null`/`undefined` for a valid field, or a string
 * error message to fail validation.
 */
export type BTFormFieldValidator<V = unknown, T = Record<string, unknown>> = (
  value: V,
  allValues: T,
) => string | null | undefined;

/**
 * Form-wide validator. Two shapes are accepted:
 *
 *   1. **Function form** — receives the full `values` snapshot, returns a
 *      partial map of `field → error` (or null). Most flexible — wrap a
 *      Zod schema, do cross-field logic, etc.
 *
 *   2. **Per-field map form** — `{ field: (value, all) => error | null }`.
 *      Ergonomic when each field has a self-contained rule. Compose with
 *      utility helpers (`required`, `pattern`, etc.) or chain via
 *      `composeValidators(...)`.
 *
 * Either form returns the same `{ field: error | null }` shape internally.
 */
export type BTFormValidator<T extends Record<string, unknown> = Record<string, unknown>> =
  | ((values: T) => Partial<Record<keyof T, string | null | undefined>>)
  | { [K in keyof T]?: BTFormFieldValidator<T[K], T> };

/**
 * Form lifecycle status. Surfaces via `state.status` so consumers can render
 * a confirmation banner / error toast without owning extra state.
 *
 *   - `'idle'`              — initial; no submit attempt yet
 *   - `'submitted-invalid'` — last submit attempt found errors
 *   - `'submitted-success'` — last submit attempt passed validation
 *                              (after the user's `onSubmit` resolved)
 */
export type BTFormStatus = 'idle' | 'submitted-invalid' | 'submitted-success';

export interface BTFormState<T extends Record<string, unknown> = Record<string, unknown>> {
  /** Current values for every field. */
  values: T;
  /** All current errors (null = valid). NOT gated on touched/submitted. */
  errors: Partial<Record<keyof T, string | null>>;
  /** Whether each field has been blurred at least once. */
  touched: Partial<Record<keyof T, boolean>>;
  /** Whether the user has attempted submit at least once. */
  submitted: boolean;
  /** Lifecycle status — see BTFormStatus. */
  status: BTFormStatus;
  /** True when no field currently has a validation error. */
  isValid: boolean;

  /**
   * Resolved error for a field — returns `null` until the field has been
   * blurred (`touched`) OR the user has attempted submit. Matches Flutter's
   * `autovalidateMode: onUserInteraction`.
   */
  errorFor: (name: keyof T) => string | null;
  /** Set a field's value (also wires the input's `onChange` automatically). */
  setField: <K extends keyof T>(name: K, value: T[K]) => void;
  /** Mark a field touched (also wires the input's `onBlur` automatically). */
  touch: (name: keyof T) => void;
  /** Reset values/touched/submitted/status to initial. */
  reset: () => void;
  /** Run the full validator and return the latest errors. */
  validate: () => Partial<Record<keyof T, string | null>>;
}

export interface BTFormProps<T extends Record<string, unknown> = Record<string, unknown>> {
  /** Initial values keyed by field `name`. Determines the field shape `T`. */
  initialValues: T;
  /**
   * Form-wide validation — function form OR per-field map. See
   * `BTFormValidator` for the shape.
   *
   * Skipped entirely when omitted (form always reports `isValid: true`).
   */
  validation?: BTFormValidator<T>;
  /**
   * Called when the user submits AND the form is valid. Receives the latest
   * `values`. Can be async; while resolving, `status` stays `'idle'` then
   * flips to `'submitted-success'` once it resolves cleanly.
   *
   * Throwing or rejecting leaves `status` at `'submitted-invalid'` and also
   * fires `onInvalid` with the current errors.
   */
  onSubmit?: (values: T) => void | Promise<void>;
  /**
   * Called when the user attempts submit but `validation` returns errors.
   * Receives the full error map. Useful for focusing the first invalid input
   * or logging.
   */
  onInvalid?: (errors: Partial<Record<keyof T, string | null>>) => void;
  /**
   * Render. Two children shapes are accepted:
   *
   *   - **JSX nodes**: any children — BT inputs that declare a `name` prop
   *     auto-wire (value/onChange/onBlur/error) via context.
   *
   *   - **Render-prop function**: `(form) => ReactNode` — receives the full
   *     `BTFormState`. Useful when you need form values to drive logic
   *     outside the inputs (e.g. conditional sections).
   */
  children: React.ReactNode | ((form: BTFormState<T>) => React.ReactNode);
  /** Extra class names applied to the `<form>` element. */
  className?: string;
  /** Forwarded to the `<form>` element. */
  id?: string;
  /**
   * Suppress browser-native HTML5 validation tooltips. Defaults to `true` —
   * `BTForm` does its own validation and double-prompting is confusing.
   */
  noValidate?: boolean;
}

/**
 * Public context value — what each BT input sees when wrapped in `<BTForm>`.
 * Inputs read the active field by `name` and call the wiring helpers.
 *
 * Keep this *narrow* — it's the public contract for input components and
 * should NOT leak internals like raw setState dispatchers.
 */
export interface BTFormContextValue<T extends Record<string, unknown> = Record<string, unknown>> {
  values: T;
  errors: Partial<Record<keyof T, string | null>>;
  touched: Partial<Record<keyof T, boolean>>;
  submitted: boolean;
  errorFor: (name: keyof T) => string | null;
  setField: <K extends keyof T>(name: K, value: T[K]) => void;
  touch: (name: keyof T) => void;
}

import { createContext, useContext } from 'react';
import type { BTFormContextValue } from './BTForm.types';

/**
 * Public BTForm context. BT inputs that declare a `name` prop subscribe via
 * `useBTForm()` and resolve their value/onChange/onBlur/error from form
 * state — no prop-drilling required.
 *
 * Provider is `BTForm` itself. Consumers should treat `null` as "not inside
 * a BTForm" and fall back to their own props / BTFormFieldContext.
 */
export const BTFormContext = createContext<BTFormContextValue | null>(null);

export function useBTForm(): BTFormContextValue | null {
  return useContext(BTFormContext);
}

export { BTForm } from './BTForm';
export { BTFormContext, useBTForm } from './BTFormContext';
export type {
  BTFormProps,
  BTFormState,
  BTFormStatus,
  BTFormContextValue,
  BTFormValidator,
  BTFormFieldValidator,
} from './BTForm.types';
